import React from "react";
import "./SearchBar.scss";

import Spinner from "../Icons/Spinner.svg";
import Search from "../Icons/Search.svg";

export default class SearchBar extends React.Component {
	state = { searching: false };

	componentDidMount() {
		SearchBar.instance = this;
	}

	onKeyDown(e) {
		if (e.key == "Enter") {
			e.preventDefault();

			window.search(e.target.textContent);
		}
	}

	render() {
		return (
			<div className="SearchBarContainer">
				<div contentEditable className="SearchBar"
					onKeyDown={e => this.onKeyDown(e)}
					onFocus={e => e.currentTarget.parentElement.classList.add("Focused")}
					onBlur={e => { if (e.currentTarget.textContent.length == 0) e.currentTarget.parentElement.classList.remove("Focused") }}/>

				<img src={this.state.searching ? Spinner : Search} className={this.state.searching ? "Spinner" : null}
					onClick={e => window.search(e.target.previousSibling.textContent)}/>

				{ this.props.children }
			</div>
		);
	}
}